solution_code:
#include <stdio.h>
#include <semaphore.h>

int main(void) {
    sem_t sem;
    sem_init(&sem, 0, 3);
    int val;

    sem_getvalue(&sem, &val);
    printf("Initial: %d\n", val);

    for (int i = 0; i < 3; i++)
        sem_wait(&sem);

    sem_getvalue(&sem, &val);
    printf("After 3 waits: %d\n", val);

    sem_destroy(&sem);
    return 0;
}

