#include <stdio.h>
#include <semaphore.h>

/* == EXEMPLE =======================================
 * sem_init anonyme avec 2 waits
 * ================================================= */
void example_unnamed(void) {
    sem_t s;
    sem_init(&s, 0, 2);
    int v;
    sem_getvalue(&s, &v); printf("Start: %d\n", v);
    sem_wait(&s); sem_wait(&s);
    sem_getvalue(&s, &v); printf("End: %d\n", v);
    sem_destroy(&s);
}
/* Resultat: Start: 2  End: 0 */

